var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이건......","JPN":"これは……","ENG":"This...","TWN":"這是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"리프노드, 식별코드 다시 확인해.","JPN":"リーフノード、識別コードをもう一度確認して。","ENG":"Leaf Node. Re-confirm the identification code.","TWN":"節點，再次確認識別代碼。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>식별코드 재확인.</color>","JPN":"<color=#ffd34c>識別コード、再確認。</color>","ENG":"<color=#ffd34c>Re-confirming identification code.</color>","TWN":"<color=#ffd34c> 識別代碼已確認。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L6_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>국방부 제 3차 차원함 전력보충계획 문서번호: 724-BA-Delta.</color>","JPN":"<color=#ffd34c>国防省第3次次元艦の戦力補充計画文書番号: 724-BA-Delta.</color>","ENG":"<color=#ffd34c>Department of Defense, 3rd Dimension Ship Power Supplementation Plan Document No.: 724-BA-Delta.</color>","TWN":"<color=#ffd34c>國防部第3批次補充戰鬥力計畫檔編號：724-BA-Delta.</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>뉴 컨스티튜션급 2번함 그레이스호퍼.</color>","JPN":"<color=#ffd34c>ニューコンスティチューション級2番艦グレースホッパー。</color>","ENG":"<color=#ffd34c>The second ship of the New Constitution class, Grace Hopper.</color>","TWN":"<color=#ffd34c> 新憲法級2號艦，葛雷斯霍普。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이전 검색결과와 일치합니다.</color>","JPN":"<color=#ffd34c>以前の検索結果と一致します。</color>","ENG":"<color=#ffd34c>Matches the previous search result.</color>","TWN":"<color=#ffd34c> 與之前搜索結果一致。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말도 안 돼!","JPN":"あり得ない……！","ENG":"No way...","TWN":"不可能！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뉴 컨스티튜션급은 아직 페이퍼 쉽이라고.","JPN":"ニューコンスティチューション級の艦船は、まだペイパーシップのはず。","ENG":"The New Constitution Class only exists on paper for now.","TWN":"新制鑑船的級別，現在還在紙上作業的階段而已啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"네임 쉽도 진수하려면 아무리 빨라도 3년은 더 있어야 하는데 2번함이라니!","JPN":"ネームシップでも進水までは最低3年は待たなきゃならないのに、2番艦だなんて！","ENG":"It should take at least 3 more years to become a name ship, but they're already at the second","TWN":"就算已命名的艦船要試航的話，最快也要3年，但這竟然是2號艦！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>식별코드는 정확합니다.</color>","JPN":"<color=#ffd34c>識別コードは間違いありません。</color>","ENG":"<color=#ffd34c>The identification code is accurate.</color>","TWN":"<color=#ffd34c> 識別代碼已確認。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>문제가 있다면 국방부 문서 라이브러리를 재 업데이트해 보시기 바랍니다.</color>","JPN":"<color=#ffd34c>問題がある場合は、国防省の文書ライブラリを再度アップデートしてください。</color>","ENG":"<color=#ffd34c>If there is an issue, please update the document library of the Department of Defense.</color>","TWN":"<color=#ffd34c> 若有問題，請重新更新國防部的資料檔案庫。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 문제라도 있나?","JPN":"何か問題か？","ENG":"Is there a problem?","TWN":"有什麼問題嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......아니. 아무것도 아냐.","JPN":"……いえ、なんでもないわ。","ENG":"No... It's nothing.","TWN":"……沒有，什麼事都沒有。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그보다 잔당들은 다 해결한 거야?","JPN":"それより、残党はすべて片づけたの？","ENG":"Did you guys finish mopping up the rest of them?","TWN":"比起這個，那些殘黨全都解決了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"보이는 녀석들은 대충...... 조직적인 저항은 끝났다고 봐야겠지.","JPN":"見渡す限りの奴らはだいたいな……組織ぐるみの抵抗は終わったと思う。","ENG":"At least the ones we could find... It's safe to say that any organized resistance is over.","TWN":"我們看得到的傢伙都解決了……或者說有組織的抵抗已經瓦解了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건 그렇고 이건 어떡할 거지?","JPN":"それはそうと、これはどうするんだ？","ENG":"Anyway, what should we do with this?","TWN":"話說回來，這該怎麼辦？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"들어서 옮기기엔 좀 큰데.","JPN":"持ち上げて移すには大きすぎると思うんだが。","ENG":"It's too big to carry.","TWN":"要移動的話未免有點太大了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아무래도 본국에 지원을 요청해야 할 것 같아.","JPN":"本国に支援を要請しないといけないみたい。","ENG":"We'll have to request reinforcements from HQ.","TWN":"看來只能向本國請求支援了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"진짜로 로스트 쉽이 있다는 게 확인됐으니까 의회에서도 병력 전개에 동의할......","JPN":"ロストシップの実在を確認できたし、議会も兵力展開に同意するはず……","ENG":"Since we confirmed that the Lost Ship does in fact exist, I'm sure Congress will agree to send more troops...","TWN":"因為我們有確實確認到失落艦船，所以議會也會同意增援兵力的……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"긴급사항을 전달합니다!","JPN":"緊急のお知らせです！","ENG":"We have an emergency!","TWN":"傳達緊急事項！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"3시 방향 고밀도 침식파 관측!","JPN":"3時方向に高密度の侵食波を観測！","ENG":"3 'o clock! High-density Corruption ray detected!","TWN":"三點鐘方向，觀測到有高密度侵蝕波！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"거리 1800......!","JPN":"距離1800……！","ENG":"1800 clicks out...!","TWN":"距離為：1800公尺……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아니, 1500! 1200! 빠릅니다!","JPN":"いや、1500！　1200！　速いです！","ENG":"No... 1500! 1200! It's coming in fast!","TWN":"不，1500……1200公尺了！越來越快了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 벌써 증원군이 온 건가?","JPN":"何だ、もう援軍が来たのか？","ENG":"What? Their reinforcements are here already?","TWN":"什麼，是援軍已經來了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......너무 빠른데?","JPN":"……早すぎないか？","ENG":"...That was too fast.","TWN":"……太快了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"코핀, 방공 시스템 자동 요격 모드로 들어갑니다!","JPN":"コフィン、防空システム自動迎撃モードに入ります！","ENG":"Coffin air defense systems will enter automatic interception mode!","TWN":"科芬防空系統，進入自動迎擊模式！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"너, 너무 빨라요! 요격 실패!","JPN":"は、速すぎます！　迎撃失敗！","ENG":"T-they're too fast! Interception failed!","TWN":"太、太快了！攔截失敗！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"데몬 타입 이상의 기동성입니다!","JPN":"デーモンタイプ以上の機動力です！","ENG":"Their maneuverability surpasses that of demon types!","TWN":"它具有鑽石級別以上的機動性能！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배, 저거 설마.......","JPN":"先輩、あれってまさか……","ENG":"Shiyoon... Could that be...","TWN":"前輩，那個難道是……"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네, 아무래도 이쪽이 주력이었던 것 같네요.","JPN":"ええ、どうやらこっちがメインのようですね。","ENG":"Yup. Looks like that's their main effort.","TWN":"嗯。看來這邊好像才是它們的主力。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"네 녀석이 이쪽에 투입된 리플레이서 지휘관인가 보군.","JPN":"貴様がここのリプレイサー指揮官か。","ENG":"You must be the Replacer commander assigned here.","TWN":"看樣子，妳這傢伙是被安排到這裡的克隆指揮官啊。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"지난번 녀석과는 달리 과묵한 편인 것 같은데, 말이 통하는 상대였으면 좋겠군.","JPN":"前の奴とは違って無口なようだが、話が通じる相手だといいな。","ENG":"You're not as chatty as the other one... Perhaps we can get along.","TWN":"和上次的那傢伙不同，看來是個沉默寡言的人呢，要是能溝通就好了"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 이쪽은 이미 상황 정리가 끝났어.","JPN":"おい、ここはもう片付いてるんだ。","ENG":"You're a bit late to the party, though.","TWN":"喂，妳。我們這邊要做的事已經結束了。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"덤비겠다면 받아 주겠지만, 승산도 없는데 굳이 피를 볼 건 없다고 생각하는데?","JPN":"戦うつもりなら相手になるが、勝ち目もないのに無駄な血を流すことはないんじゃないか？","ENG":"We can fight if you want, but what's the point of shedding any blood when the odds are stacked against you?","TWN":"如果妳要攻過來的話，我們也會應戰的。但是在沒有勝算情況下，妳認為還有必要見血嗎？"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우리도 목적은 달성했으니 조용히 물러난다면 쫓지는 않을 거야. 어때?","JPN":"我々も目的は達成したし、おとなしく下がるなら追いかけたりはしないが、どうだ？","ENG":"We've accomplished our objectives here, so we won't pursue you if you leave quietly. Deal?","TWN":"我們的目的已經達成了，如果妳乖乖撤退的話，我們也不會追擊妳，怎麼樣？"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"오랜만이네.","JPN":"久しぶりだな。","ENG":"Long time no see...","TWN":"好久不見了呢。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......제자야.","JPN":"……弟子よ。","ENG":"...Shiyoon.","TWN":"……徒弟啊。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우리가 저 녀석이랑 만난 적이 있었나?","JPN":"私たち、あいつと会ったことあるか？","ENG":"Have we met her before?","TWN":"我們有見過那個傢伙嗎？"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"난 기억이 없는데.","JPN":"私にはそんな覚えないんだが。","ENG":"I don't recall.","TWN":"我不記得了。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 처음 보는데요?","JPN":"僕も初対面です。","ENG":"Same here.","TWN":"我應該也是第一次見到她啊？"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"비슷하게 생긴 사람과 헷갈린 게 아닐까요?","JPN":"人違いじゃないでしょうか？","ENG":"Maybe she's got us confused with someone else?","TWN":"她是不是把你和其他人搞混了呢？"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아니면 혹시 미나 양이 아는 사람인가요?","JPN":"それとも、ミナさんの知り合いですか？","ENG":"Or perhaps you know her Mina?","TWN":"要不然，就是米娜認識的人？"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"전혀.","JPN":"いや、全然。","ENG":"Not at all.","TWN":"不可能。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이따위 테러리스트 놈들 중에 내가 아는 사람이 있을 리가 없......","JPN":"こんなテロリストのやつらに、知り合いなんているはず……","ENG":"How would I know a terrorist...","TWN":"這些恐怖份子中，怎麼可能有我認識的人啊……"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"섭섭한걸. 벌써 내 목소리를 잊어 버리다니.","JPN":"さみしいな。もう私の声を忘れてしまったなんて。","ENG":"I'm disappointed. You forgot my voice already?","TWN":"太難過了，妳竟然已經忘記我的聲音了。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"유미나.","JPN":"ヤナギ・ミナ。","ENG":"Yoo Mina.","TWN":"劉米娜。"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뭐? 내 이름은 어떻게 알고 있는 거야?","JPN":"……なっ！　どうして私の名前を知ってるの？","ENG":"...What? How do you know my name?","TWN":"……什麼？妳是怎麼知道我的名字的？"},"stage":{"bg":"MAINSTREAM_314011","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"나야.","JPN":"私だよ。","ENG":"It's me.","TWN":"是我啊。"},"stage":{"bg":"MAINSTREAM_314012","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌......","JPN":"あなたは……","ENG":"You're...","TWN":"妳……"},"stage":{"bg":"MAINSTREAM_314012","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나......","JPN":"ナ……","ENG":"Na...","TWN":"我……"},"stage":{"bg":"MAINSTREAM_314012","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나래......?","JPN":"ナルミ……？","ENG":"Narae...?","TWN":"娜拉……?"},"stage":{"bg":"MAINSTREAM_314012","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"뭐, 그런 이름으로 불리던 때도 있었지.","JPN":"まあ、そんな名前で呼ばれていた時もあったな。","ENG":"Ah, yes. I used to go by that name.","TWN":"嗯，我曾經有段時間，我叫這個名字。"},"stage":{"bg":"MAINSTREAM_314012","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"지금은 리플레이서 비숍이라는 코드명이 더 익숙하지만.","JPN":"今は「リプレイサー・ビショップ」というコードネームの方がしっくりくるけど。","ENG":"I go by the code name Replacer Bishop now.","TWN":"不過現在，我比較習慣克隆·大主教這個代碼名。"},"stage":{"bg":"MAINSTREAM_314012","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"어쨌든 오랜만이야.","JPN":"とにかく久しぶりだ。","ENG":"Anyway, it's been a while.","TWN":"不管怎麼說，我們都好久不見了。"},"stage":{"bg":"MAINSTREAM_314012","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"여전히 잘도 살아 있구나.","JPN":"相変わらず、しぶとく生きているようだな。","ENG":"It's nice to see you're still alive.","TWN":"妳還活著啊。"},"stage":{"bg":"MAINSTREAM_314012","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저, 정말 나래야?","JPN":"ほ、本当にナルミなの？","ENG":"Are you really Narae...?","TWN":"妳、妳真的是娜拉嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"살아...... 있었어......?","JPN":"生きて……いたの……？","ENG":"You... You're still alive...?","TWN":"妳還活著……嗎……？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 리, 리플레이서라니...... 그게 무슨......?","JPN":"だけど、リ、リプレイサーだなんて……一体なにが……？","ENG":"But... Replacer? What do you mean?","TWN":"可是，那不是克、克隆集團嗎……這是為什麼……？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"왜, 살아 있어서 불만이야?","JPN":"なに、私が生きてるのが不満なのか？","ENG":"What? You don't look happy to see me!","TWN":"怎麼， 我還活著，妳不滿意嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니야!","JPN":"違うよ！","ENG":"No!","TWN":"怎麼會！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나...... 나는, 네가 그날......","JPN":"私……私は、ナルミがあの日……","ENG":"I... I just... That day...","TWN":"但是……我以為，妳那天已經……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"죽은 줄 알았다고?","JPN":"死んだと思った？","ENG":"You thought I was dead?","TWN":"妳以為我死了？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그래. 나도 한동안은 그런 줄 알았지.","JPN":"だよね。私もしばらくはそう思ってた。","ENG":"Yes. That's what I thought for a while too.","TWN":"是啊，我有段時間也是這樣想的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이봐.","JPN":"おい。","ENG":"Hey.","TWN":"喂。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우리 신입이랑 무슨 사정이 있는지는 모르겠지만, 다시 한 번 제안하지.","JPN":"新人との間で何があったかは知らないが、もう一度提案しよう。","ENG":"I don't know what business you have with the rookie, but think about what I said.","TWN":"我雖然不知道你跟我們的新人有什麼關係，但是容我再提醒一下。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"여기선 물러서는 게 좋아.","JPN":"ここは下がったほうがいい。","ENG":"It'd be in your best interest to turn back this time.","TWN":"在這裡，妳還是退下會比較好。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 리플레이서 나이트인지 뭔지 하는 네 동료가 어떤 꼴이 됐는지는 잘 알겠지?","JPN":"あのリプレイサー・ナイトだかなんだかが、最後どうなったかは知ってるよな？","ENG":"You probably know how your friend turned out... Replacer Knight, was it?","TWN":"妳應該很清楚那個克隆·騎士什麼的，在上次戰鬥中變成什麼樣子了吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너 혼자서 덤벼 봐야 승산은 제로다.","JPN":"お前一人でかかって来ても勝ち目はゼロだ。","ENG":"Your chance of winning here is zero to none.","TWN":"只有一個人的話，妳根本沒有勝算。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그래?","JPN":"そう？","ENG":"Is that so?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그럼 혼자가 아니면 되겠네.","JPN":"じゃあ、1人じゃないならいいんだな。","ENG":"Then what if I bring some friends?","TWN":"那只要不是一個人就可以了吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"침식파 밀도, 급격히 상승 중!","JPN":"侵食波密度、急激に上昇中！","ENG":"Corruption ray density is rapidly increasing!","TWN":"侵蝕波密度在急速上升中！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"경고. 교전 지역으로 집결하는 다수의 침식체 군집이 관측되었습니다!","JPN":"警告。交戦地域に集結する多数の浸食体群が観測されました！","ENG":"Warning! Multiple Corrupted Object clusters detected near the area!","TWN":"警告！觀測到多數侵蝕體群在交戰地區集結！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......끝까지 해 보겠다는 거군.","JPN":"……引かないつもりのようだな。","ENG":"...So that's how you want to play.","TWN":"……看來這傢伙就是要打到底。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 굳이 싸우겠다면 말릴 필요는 없겠지.","JPN":"わかった。どうしても戦いたいなら止める必要もないだろう。","ENG":"Okay then. If it's a fight you want, I'll give it to you.","TWN":"好吧。如果要開打的話，也沒有警告的必要了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주시윤! 적이 합류하기 전에 단숨에 끝낸......!","JPN":"シリュウ！　敵が合流する前に、一気に終わらせ……！","ENG":"Shiyoon! Take the enemy down before they join up with the others!","TWN":"周時雲！在敵人加入之前，我們一口氣解決……！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자, 잠깐! 소대장! 싸우면 안 돼! 내 친구라고!","JPN":"ま、待って小隊長！　戦うのはやめて！　私の友達なの！","ENG":"W-wait! Commander! Don't fight her! She's my friend!","TWN":"等、等一下！小隊長！不要打！這是我朋友！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐 하는 짓이야! 신입 애송이! 떨어지지 못해?!","JPN":"何のつもりだ、新人！　離れろ！","ENG":"What are you doing? Get off me, rookie! That's an order!","TWN":"妳在幹什麼！新人！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하, 하지만!","JPN":"で、でも……！","ENG":"B-but!","TWN":"但、但是！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그래...... 잘 이야기를 해 보면...... 어쩌면......","JPN":"そ、そうだ……ちゃんと話せば……もしかしたら……","ENG":"I-I know... We might be able to talk through this... Maybe then...","TWN":"對、對了，我們如果好好談一談的話……說不定……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"......그 가증스런 모습도 여전하네. 유미나.","JPN":"……その善人ぶりも相変わらずだな、ミナ。","ENG":"...You're still as despicable as ever, Mina.","TWN":"……妳那令人憎惡的嘴臉還是一樣呢，劉米娜。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"이런 것도 참 일관성이 있다고 해야 할까?","JPN":"そういうところ、すごく一貫性があるっていえばいいのか？","ENG":"People never change, do they?","TWN":"還是說這就是妳一貫的處事風格？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"덕분에 내가 해야 할 일이 뭔지 다시 한 번 잘 알게 됐어.","JPN":"おかげで、私が何をすべきか改めて確認できたよ。","ENG":"Thanks to you, I finally understand my life's purpose.","TWN":"拜妳所賜，我再次確定我該做的事情是什麼了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"유미나.","JPN":"ヤナギ・ミナ。","ENG":"Mina.","TWN":"劉．米．娜。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"너만은 반드시 내 손으로 죽여 주겠어!","JPN":"お前だけは必ずこの手で殺してやる！","ENG":"I'll make sure to kill you with my own hands!","TWN":"只有妳，我一定要親手殺了妳！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};